```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper: map table_name -> C++ type
inline auto make_table_type_map() {
  return std::map<std::string, std::string>{
      {"Student", "Student"},
      {"Course",  "Course"},
      {"Score",   "Score"},
      {"Major",   "Major"},
  };
}

// Insert records into a given table using sqlgen::insert
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  if (records.empty()) return;

  // Determine at compile-time which table we are targeting.
  // Caller is expected to pass the matching C++ type T for the table_name.
  // We only use table_name at runtime for basic sanity checking.
  const auto table_map = make_table_type_map();
  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::runtime_error("Unknown table name: " + table_name);
  }

  // Optional sanity: check that T matches the table_name we expect.
  // This is best‑effort and only guards the obvious mismatches.
  bool type_matches = false;
  if constexpr (std::is_same_v<T, Student>) {
    type_matches = (table_name == "Student");
  } else if constexpr (std::is_same_v<T, Course>) {
    type_matches = (table_name == "Course");
  } else if constexpr (std::is_same_v<T, Score>) {
    type_matches = (table_name == "Score");
  } else if constexpr (std::is_same_v<T, Major>) {
    type_matches = (table_name == "Major");
  } else {
    throw std::runtime_error("Unsupported record type for sqlgen insertion");
  }

  if (!type_matches) {
    throw std::runtime_error(
        "Type T does not correspond to table '" + table_name + "'");
  }

  // Connect and insert
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error(
        "Failed to connect to database: " +
        conn_res.error().message());  // sqlgen::error
  }
  auto& conn = conn_res.value();

  auto insert_res = sqlgen::insert(records)(conn);
  if (!insert_res) {
    throw std::runtime_error(
        "Failed to insert records into " + table_name + ": " +
        insert_res.error().message());
  }
}

// Modify a record by primary key ID
// record_id is passed as string for simplicity; we will convert it to the
// appropriate type depending on table_name.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const rfl::json::value& new_value) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error(
        "Failed to connect to database: " +
        conn_res.error().message());
  }
  auto& conn = conn_res.value();

  // We implement updates via raw SQL because we want to choose table and
  // primary key dynamically at runtime based on table_name.
  std::string pk_name;
  bool        pk_is_text = false;  // to decide quoting
  if (table_name == "Student") {
    pk_name    = "SNo";
    pk_is_text = true;  // VARCHAR
  } else if (table_name == "Course") {
    pk_name    = "CID";
    pk_is_text = false; // integer (auto-increment)
  } else if (table_name == "Score") {
    pk_name    = "ScID";
    pk_is_text = false;
  } else if (table_name == "Major") {
    pk_name    = "MID";
    pk_is_text = false;
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }

  // Convert new_value to SQL literal
  auto to_sql_literal = [](const rfl::json::value& v) -> std::string {
    using v_t = rfl::json::value;
    if (v.is_null()) {
      return "NULL";
    } else if (v.is_bool()) {
      return v.as_bool() ? "1" : "0";
    } else if (v.is_number()) {
      return std::to_string(v.as_number());
    } else if (v.is_string()) {
      std::string s = v.as_string();
      // Escape single quotes for SQL
      std::string escaped;
      escaped.reserve(s.size() + 2);
      escaped.push_back('\'');
      for (char c : s) {
        if (c == '\'') escaped.push_back('\'');
        escaped.push_back(c);
      }
      escaped.push_back('\'');
      return escaped;
    } else {
      // For other JSON types (array/object) we serialize to JSON string
      auto json_str = rfl::json::write(v);
      std::string s = json_str;
      std::string escaped;
      escaped.reserve(s.size() + 2);
      escaped.push_back('\'');
      for (char c : s) {
        if (c == '\'') escaped.push_back('\'');
        escaped.push_back(c);
      }
      escaped.push_back('\'');
      return escaped;
    }
  };

  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = " +
                    to_sql_literal(new_value) + " WHERE " + pk_name + " = ";
  if (pk_is_text) {
    // Quote text primary key
    std::string escaped;
    escaped.reserve(record_id.size() + 2);
    escaped.push_back('\'');
    for (char c : record_id) {
      if (c == '\'') escaped.push_back('\'');
      escaped.push_back(c);
    }
    escaped.push_back('\'');
    sql += escaped;
  } else {
    sql += record_id;
  }
  sql += ";";

  auto exec_res = sqlgen::exec(conn, sql);
  if (!exec_res) {
    throw std::runtime_error(
        "Failed to modify record in " + table_name + ": " +
        exec_res.error().message());
  }
}

// Delete a record by primary key ID
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error(
        "Failed to connect to database: " +
        conn_res.error().message());
  }
  auto& conn = conn_res.value();

  std::string pk_name;
  bool        pk_is_text = false;
  if (table_name == "Student") {
    pk_name    = "SNo";
    pk_is_text = true;
  } else if (table_name == "Course") {
    pk_name    = "CID";
    pk_is_text = false;
  } else if (table_name == "Score") {
    pk_name    = "ScID";
    pk_is_text = false;
  } else if (table_name == "Major") {
    pk_name    = "MID";
    pk_is_text = false;
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }

  std::string sql =
      "DELETE FROM " + table_name + " WHERE " + pk_name + " = ";
  if (pk_is_text) {
    std::string escaped;
    escaped.reserve(record_id.size() + 2);
    escaped.push_back('\'');
    for (char c : record_id) {
      if (c == '\'') escaped.push_back('\'');
      escaped.push_back(c);
    }
    escaped.push_back('\'');
    sql += escaped;
  } else {
    sql += record_id;
  }
  sql += ";";

  auto exec_res = sqlgen::exec(conn, sql);
  if (!exec_res) {
    throw std::runtime_error(
        "Failed to delete record from " + table_name + ": " +
        exec_res.error().message());
  }
}
