    } else if (v.is_number()) {
      return std::to_string(v.as_number());
    } else if (v.is_string()) {
      std::string s = v.as_string();
      // Escape single quotes for SQL
      std::string escaped;
      escaped.reserve(s.size() + 2);
      escaped.push_back('\'');
      for (char c : s) {
        if (c == '\'') escaped.push_back('\'');
        escaped.push_back(c);
      }
      escaped.push_back('\'');
      return escaped;
