/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  try {
    // Open (or create) the SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Create a schema manager for this connection
    sqlgen::sqlite::Schema schema(conn);

    // Drop Product table if it exists, then create it from the Product struct
    schema.dropTableIfExists<Product>();
    schema.createTable<Product>();

    // Begin transaction for batch insert
    conn.beginTransaction();

    // Create a generic table handler for Product
    sqlgen::sqlite::Table<Product> product_table(conn);

    // Perform batch insert
    product_table.insertMany(products);

    // Commit transaction if all inserts succeed
    conn.commitTransaction();

    return true;
  } catch (const std::exception&) {
    // On any error, try to roll back and return false
    try {
      // It's safe to construct a connection again here just to rollback
      sqlgen::sqlite::Connection conn("test_db.sqlite");
      conn.rollbackTransaction();
    } catch (...) {
      // Ignore rollback failures
    }
    return false;
  }
