namespace query_active_users_posts {

struct User {
  static constexpr const char* tablename = "User";

  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  static constexpr const char* tablename = "Post";

  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
  // 1. Connect to SQLite database "test_db.sqlite"
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // 2. Create `User` and `Post` tables if they do not exist
  //    sqlgen can usually generate CREATE TABLE statements from the structs
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS User (
      user_id   INTEGER PRIMARY KEY,
      username  VARCHAR(50) NOT NULL
    );
  )");

  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Post (
      post_id    INTEGER PRIMARY KEY,
      user_id    INTEGER NOT NULL,
      created_at DATETIME NOT NULL,
      FOREIGN KEY(user_id) REFERENCES User(user_id)
    );
  )");

  // 3. Define/view mapping query:
  //    Users with at least one post between 2025-12-01 and 2025-12-31 (inclusive).
  //
  //    We use a view so that sqlgen can map results into ActiveUser.
  conn.execute(R"(
    DROP VIEW IF EXISTS ActiveUserView;
  )");

  conn.execute(R"(
    CREATE VIEW ActiveUserView AS
    SELECT DISTINCT u.user_id AS user_id,
                    u.username AS username
    FROM User u
    INNER JOIN Post p ON u.user_id = p.user_id
    WHERE p.created_at >= DATE('2025-12-01')
      AND p.created_at <= DATE('2025-12-31');
  )");

  // 4. Query the view and return user information
  sqlgen::sqlite::Storage storage(conn);

  // sqlgen::select<ActiveUser>() should map columns from ActiveUserView to ActiveUser
  auto results = storage.select<ActiveUser>();

  return results;
}

}  // namespace query_active_users_posts
