    (student_count, "student_count"),
    (avg_grade, "avg_grade"))

namespace query_course_enrollment_stats {

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // 2. Create Course and Enrollment tables
  {
    sqlite::Transaction tx(conn);

    // Create tables if they do not exist
    conn.exec(R"SQL(
      CREATE TABLE IF NOT EXISTS Course (
        course_id   INTEGER PRIMARY KEY,
        title       VARCHAR(100) NOT NULL
      );
    )SQL");

    conn.exec(R"SQL(
      CREATE TABLE IF NOT EXISTS Enrollment (
        enrollment_id INTEGER PRIMARY KEY,
        course_id     INTEGER,
        grade         REAL,
        FOREIGN KEY(course_id) REFERENCES Course(course_id)
      );
    )SQL");

    tx.commit();
  }

  // 3. Query the database to calculate number of students enrolled per course
  //    and average grade per course (ignoring NULLs)
  std::vector<CourseStatsView> rows;

  {
    sqlite::Statement stmt(conn,
      "SELECT c.title AS title, "
      "       COUNT(e.enrollment_id) AS student_count, "
      "       AVG(e.grade) AS avg_grade "
      "FROM Course c "
      "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
      "GROUP BY c.course_id, c.title;");

    while (stmt.step()) {
      CourseStatsView row{};
      // title
      row.title = stmt.get<std::string>(0);
      // COUNT(...) in SQLite is never NULL; map directly to int
      row.student_count = stmt.get<int>(1);
      // AVG(...) can be NULL; use std::optional<double>
      if (stmt.is_null(2)) {
        row.avg_grade = std::nullopt;
      } else {
        row.avg_grade = stmt.get<double>(2);
      }
      rows.push_back(std::move(row));
    }
  }

  // 4. Return the results as a vector of CourseStats
  std::vector<CourseStats> result;
  result.reserve(rows.size());
  for (const auto& r : rows) {
    result.push_back(CourseStats{
        r.title,
        r.student_count,
        r.avg_grade
    });
  }

  return result;
}

}  // namespace query_course_enrollment_stats
