std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // 2. Create tables: Customer, Order, OrderItem, Product
  //    (CREATE TABLE IF NOT EXISTS semantics are handled by sqlgen::create_table)
  create_table<Customer>(conn);
  create_table<Product>(conn);
  create_table<Order>(conn);
  create_table<OrderItem>(conn);

  // 3. Query the database to retrieve all products purchased by a specific customer
  //
  //    Reference SQL:
  //    SELECT p.name, o.order_date, oi.quantity
  //    FROM Customer c
  //    JOIN "Order" o ON c.customer_id = o.customer_id
  //    JOIN OrderItem oi ON o.order_id = oi.order_id
  //    JOIN Product p ON oi.product_id = p.product_id
  //    WHERE c.customer_id = ?
  //    ORDER BY o.order_date DESC;

  // We use a raw SQL query through sqlgen's SQLite wrapper to fetch into
  // the rfl-reflected PurchaseHistory struct.
  std::vector<PurchaseHistory> results;

  // Prepare and execute the query with parameter binding
  auto stmt = conn.prepare(
      "SELECT p.name AS product_name, "
      "       o.order_date AS order_date, "
      "       oi.quantity AS quantity "
      "FROM Customer c "
      "JOIN \"Order\" o ON c.customer_id = o.customer_id "
      "JOIN OrderItem oi ON o.order_id = oi.order_id "
      "JOIN Product p ON oi.product_id = p.product_id "
      "WHERE c.customer_id = ? "
      "ORDER BY o.order_date DESC;");

  stmt.bind(1, customer_id);

  while (stmt.step()) {
    PurchaseHistory ph;

    // Column 0: product_name (TEXT)
    ph.product_name = stmt.get<std::string>(0);

    // Column 1: order_date (TEXT -> Timestamp)
    // sqlgen::Timestamp can usually be constructed from string,
    // so we read it as std::string and then rely on the Timestamp
    // parsing the given format.
    auto date_str = stmt.get<std::string>(1);
    ph.order_date = sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">{date_str};

    // Column 2: quantity (INTEGER)
    ph.quantity = stmt.get<int>(2);

    results.push_back(std::move(ph));
  }

  // 4. Return the results as a vector of PurchaseHistory
  return results;
}

}  // namespace query_customer_purchase_history
