  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;

  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to the SQLite database "test_db.sqlite"
  Database db("test_db.sqlite");

  // Define table wrappers for Product and Sale
  Table<Product> product;
  Table<Sale> sale;

  // Build the query:
  // SELECT p.category,
  //        SUM(s.quantity) AS total_qty,
  //        SUM(s.amount)   AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;

  auto p = product.as("p");
  auto s = sale.as("s");

  auto q = select(
              p->category,
              sum(s->quantity).as("total_qty"),
              sum(s->amount).as("total_amt"))
           .from(p)
           .join(s, p->product_id == s->product_id)
           .group_by(p->category)
           .having(sum(s->amount) > 5000.0);

  // Execute into intermediate view struct (matches the SELECT columns)
  struct Row {
    std::string category;
    int total_qty;
    double total_amt;
  };

  std::vector<Row> rows = db.query<Row>(q);

  // Map to the requested result type
  std::vector<CategoryReport> result;
  result.reserve(rows.size());
  for (const auto& r : rows) {
    result.push_back(CategoryReport{r.category, r.total_qty, r.total_amt});
  }

  return result;
}

}  // namespace query_product_sales_report
