  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using namespace sqlgen::sqlite;

  // Open connection to SQLite database
  Connection conn("test_db.sqlite");

  // Start with base SELECT query
  std::string query = "SELECT book_id, title, author, year, genre, price FROM Book";
  std::vector<sqlgen::Value> params;
  bool has_where = false;

  auto append_condition = [&](const std::string& cond) {
    if (!has_where) {
      query += " WHERE ";
      has_where = true;
    } else {
      query += " AND ";
    }
    query += cond;
  };

  // Add dynamic conditions based on filters

  // title_keyword -> title LIKE ?
  if (filters.title_keyword.has_value()) {
    append_condition("title LIKE ?");
    std::string pattern = "%" + *filters.title_keyword + "%";
    params.emplace_back(pattern);
  }

  // min_year -> year >= ?
  if (filters.min_year.has_value()) {
    append_condition("year >= ?");
    params.emplace_back(*filters.min_year);
  }

  // genre -> genre = ?
  if (filters.genre.has_value()) {
    append_condition("genre = ?");
    params.emplace_back(*filters.genre);
  }

  // max_price -> price <= ?
  if (filters.max_price.has_value()) {
    append_condition("price <= ?");
    params.emplace_back(*filters.max_price);
  }

  // Prepare and execute the statement through sqlgen
  Statement stmt = conn.prepare(query);

  // Bind parameters in order
  for (std::size_t i = 0; i < params.size(); ++i) {
    stmt.bind(static_cast<int>(i + 1), params[i]);
  }

  std::vector<Book> results;

  // Use sqlgen's mapping to read rows into Book
  while (stmt.step()) {
    Book b;
    // Assuming columns are in the same order as in SELECT
    b.book_id = stmt.column<int>(0);
    b.title   = stmt.column<std::string>(1);
    b.author  = stmt.column<std::string>(2);
    b.year    = stmt.column<int>(3);
    b.genre   = stmt.column<std::string>(4);
    b.price   = stmt.column<double>(5);
    results.push_back(std::move(b));
  }

  return results;
}

}  // namespace query_search_books_by_criteria
