#include <gtest/gtest.h>
#include <vector>
#include <string>

#include "schema_create_complex_table.hpp"

namespace schema_create_complex_table {

/**
 * Test Case: Test creation of complex table with constraints
 * 
 * Test Scenario:
 * - Call create_complex_table
 * - Verify the table exists in the database schema
 * - Test constraints:
 *   - Try inserting duplicate username (should fail)
 *   - Try inserting duplicate email (should fail)
 */
TEST(sqlite, create_complex_table) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup before test
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<UserProfile>(conn);

  // 1. Call create_complex_table
  bool success = create_complex_table();
  EXPECT_TRUE(success);

  // 2. Verify the table exists
  // We can verify by trying to insert a record
  UserProfile user1{
      .user_id = 1,
      .username = "user1",
      .email = "user1@example.com",
      .age = 20,
      .bio = "Bio 1",
      .created_at = "2025-01-01 00:00:00",
      .is_verified = true};

  auto insert_result = insert(conn, std::vector{user1});
  EXPECT_TRUE(insert_result.has_value());

  // 3. Test constraints

  // Duplicate username
  UserProfile user2{
      .user_id = 2,
      .username = "user1", // Duplicate
      .email = "user2@example.com",
      .age = 25,
      .bio = "Bio 2",
      .created_at = "2025-01-02 00:00:00",
      .is_verified = false};

  auto insert_dup_username = insert(conn, std::vector{user2});
  EXPECT_FALSE(insert_dup_username.has_value()); // Should fail

  // Duplicate email
  UserProfile user3{
      .user_id = 3,
      .username = "user3",
      .email = "user1@example.com", // Duplicate
      .age = 30,
      .bio = "Bio 3",
      .created_at = "2025-01-03 00:00:00",
      .is_verified = true};

  auto insert_dup_email = insert(conn, std::vector{user3});
  EXPECT_FALSE(insert_dup_email.has_value()); // Should fail

  // Valid insert
  UserProfile user4{
      .user_id = 4,
      .username = "user4",
      .email = "user4@example.com",
      .age = 22,
      .bio = "Bio 4",
      .created_at = "2025-01-04 00:00:00",
      .is_verified = false};

  auto insert_valid = insert(conn, std::vector{user4});
  EXPECT_TRUE(insert_valid.has_value());
}

}  // namespace schema_create_complex_table

