#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_complex_table {

struct UserProfile {
  // user_id INTEGER PRIMARY KEY AUTOINCREMENT
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;

  // username VARCHAR(50) NOT NULL UNIQUE
  // (length is typically handled via SQL type mapping or annotations;
  //  sqlgen::Unique enforces UNIQUE, std::string is NOT NULL by default
  //  unless wrapped in an optional type)
  sqlgen::Unique<std::string> username;

  // email VARCHAR(100) NOT NULL UNIQUE
  sqlgen::Unique<std::string> email;

  // age INTEGER CHECK(age >= 18)
  int age;

  // bio TEXT
  std::string bio;

  // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  sqlgen::DateTime created_at;

  // is_verified BOOLEAN DEFAULT 0
  bool is_verified;
};

/**
 * Function: Create a table with various constraints and data types.
 * 
 * @return true if creation succeeds, false otherwise
 */
bool create_complex_table() {
  try {
    // Open / create the SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Build a schema object
    sqlgen::Schema schema;

    // Map the C++ struct to a SQL table named "UserProfile"
    // The sqlgen type wrappers (PrimaryKey, Unique, DateTime, bool) will
    // translate into appropriate SQLite column definitions.
    auto& table = schema.add_table<UserProfile>("UserProfile");

    // Add column-level and table-level constraints that sqlgen does not
    // infer automatically from the types.

    // age INTEGER CHECK(age >= 18)
    // We add an explicit CHECK constraint on the "age" column.
    table.add_check("age", "age >= 18");

    // created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    table.set_default("created_at", "CURRENT_TIMESTAMP");

    // is_verified BOOLEAN DEFAULT 0
    // In SQLite, boolean is typically stored as INTEGER 0/1.
    table.set_default("is_verified", "0");

    // Generate and execute the CREATE TABLE statement on the database.
    sqlgen::sqlite::create_table(db, schema, "UserProfile");

    return true;
  } catch (const std::exception&) {
    // In a real system, log the exception message here.
    return false;
  }
}

}  // namespace schema_create_complex_table
