#pragma once

#include <stdexcept>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Basic validation
  if (amount <= 0.0) {
    return false;
  }
  if (from_account_id == to_account_id) {
    // No-op transfer; treat as success.
    return true;
  }

  // Open connection to the SQLite database.
  sqlgen::sqlite::Database db("test_db.sqlite");

  try {
    // Start transaction
    db.beginTransaction();

    // Bind the Account struct to the database for type-safe operations.
    sqlgen::Database<sqlgen::sqlite::Database> orm(db);
    orm.attach<Account>("Account");

    // Load sender account
    auto from_opt = orm.get<Account>(from_account_id);
    if (!from_opt) {
      db.rollback();
      return false;
    }

    // Check sufficient funds
    if (from_opt->balance < amount) {
      db.rollback();
      return false;
    }

    // Load receiver account
    auto to_opt = orm.get<Account>(to_account_id);
    if (!to_opt) {
      db.rollback();
      return false;
    }

    // Perform updates in-memory
    from_opt->balance -= amount;
    to_opt->balance   += amount;

    // Persist changes
    orm.update(*from_opt);
    orm.update(*to_opt);

    // Commit if everything succeeded
    db.commit();
    return true;

  } catch (const std::exception&) {
    // Any error should rollback the transaction.
    try {
      db.rollback();
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
