namespace update_eas_table {

void update_eas_table() {
  // Ensure the database and all original tables exist
  design_eas_database_with_major();

  // Connect to the SQLite database and perform schema updates
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column `Grade` to the table `Score`,
        //    type CHAR(1), NOT NULL with a default value.
        //    (Default is required so existing rows satisfy NOT NULL.)
        return sqlgen::exec(
            conn,
            "ALTER TABLE Score "
            "ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'F';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify the column type of `Age` in the table `Student`
        //    to INT, allowing NULL values.
        //
        // SQLite has limited direct ALTER support; type changes are
        // normally done via table reconstruction. For this task we
        // assume `Age` exists and we update its declared type in-place
        // using a pragma-based rebuild.
        //
        // The sequence below:
        //   - Start a transaction
        //   - Rename old table
        //   - Create a new Student table with Age as INT NULL
        //   - Copy data
        //   - Drop old table
        //   - Commit
        //
        // Since the original Student struct in eas_common.hpp does not
        // declare Age, we perform the migration purely via SQL.
        //
        // Step 1: begin transaction
        auto r = sqlgen::exec(conn, "BEGIN TRANSACTION;");
        if (!r) return r;

        // Step 2: rename old Student table
        r = sqlgen::exec(conn, "ALTER TABLE Student RENAME TO Student_old;");
        if (!r) {
          sqlgen::exec(conn, "ROLLBACK;").value();
          return r;
        }

        // Step 3: create new Student table with Age INT NULL.
        // We recreate columns as described in the prompt:
        //   Student(SNo, Name, Sex, Birthday, Major, Scores, Remark, Age)
        // and set Age INT NULL.
        r = sqlgen::exec(
            conn,
            "CREATE TABLE Student ("
            "  SNo    VARCHAR(10) PRIMARY KEY,"
            "  Name   VARCHAR(30) NOT NULL,"
            "  Sex    INT NOT NULL DEFAULT 1,"
            "  Birthday DATETIME,"
            "  Major  INTEGER,"
            "  Scores REAL,"
            "  Remark TEXT,"
            "  Age    INT"
            ");");
        if (!r) {
          sqlgen::exec(conn, "ROLLBACK;").value();
          return r;
        }

        // Step 4: copy data from old table to new table.
        // The old Student table is expected to contain Age already,
        // so we copy it directly.
        r = sqlgen::exec(
            conn,
            "INSERT INTO Student (SNo, Name, Sex, Birthday, Major, Scores, "
            "Remark, Age) "
            "SELECT SNo, Name, Sex, Birthday, Major, Scores, Remark, Age "
            "FROM Student_old;");
        if (!r) {
          sqlgen::exec(conn, "ROLLBACK;").value();
          return r;
        }

        // Step 5: drop the old Student table
        r = sqlgen::exec(conn, "DROP TABLE Student_old;");
        if (!r) {
          sqlgen::exec(conn, "ROLLBACK;").value();
          return r;
        }

        // Step 6: commit transaction
        return sqlgen::exec(conn, "COMMIT;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop the table `Major`.
        return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
      })
      .value();
}

