/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to SQLite database "test_db.sqlite"
  sqlgen::sqlite::connection conn{"test_db.sqlite"};

  // Map structs to database tables
  auto department_table = sqlgen::table<Department>("Department");
  auto project_table = sqlgen::table<Project>("Project");

  // We want all departments, including those without projects.
  // SQLite does not support RIGHT JOIN directly, so we emulate a RIGHT JOIN
  // (Project RIGHT JOIN Department) as a LEFT JOIN with reversed roles:
  //
  //   SELECT d.name, p.name
  //   FROM Department d
  //   LEFT JOIN Project p ON d.department_id = p.department_id;
  //
  // This returns every department, with project columns NULL when no project exists.
  //
  // With sqlgen, we read the joined data and manually map it into DepProj.

  std::vector<DepProj> result;

  // Build and execute the LEFT JOIN query using the sqlgen read API
  sqlgen::read<
      Department,
      Project>(
      conn,
      // Join condition: Department.department_id == Project.department_id
      sqlgen::left_join(project_table,
                        sqlgen::on(department_table(&Department::department_id) ==
                                   project_table(&Project::department_id))),
      // Row handler: convert each joined row into DepProj
      [&](const Department& d, const std::optional<Project>& p_opt) {
        // Department is always present in a LEFT JOIN from Department
        DepProj dp;
        dp.department_name = d.name;

        // For departments without projects, p_opt will be std::nullopt.
        // The DepProj struct requires a project_name string; to "include"
        // departments without projects while still returning DepProj, we
        // represent missing projects with an empty project_name.
        if (p_opt) {
          dp.project_name = p_opt->name;
        } else {
          dp.project_name.clear();
        }

        result.push_back(std::move(dp));
      });

  return result;
}

}  // namespace right_join_departments_projects
