  // typical sqlgen patterns for column references.
  auto query = backend
      .select(qa.id, qa.name, qb.score)
      .from(qa)
      .join(qb, qa.id == qb.a_id)
      .where(qb.score > 10 && qa.name.like("%x%"))
      .order_by(qb.score.desc(), qa.name.asc())
      .limit(50);

