namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Connects to the SQLite database "test_db.sqlite", ensures the Event table
 * exists, inserts the provided events, runs a query to extract date/time
 * parts and compute duration, and returns the results as a vector of
 * TemporalAnalysis.
 *
 * The temporal analysis performed includes:
 *  - Extract individual date/time components from start_time
 *  - Calculate days between start_time and end_time
 *  - Determine weekday information for events
 *  - Convert timestamps to Unix epoch format
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
  using namespace sqlgen;

  // Open (or create) the SQLite database
  sqlite::Database db("test_db.sqlite");

  // Define schema for Event table using sqlgen metadata
  auto eventTable = make_table_metadata<Event>(
      "Event",
      make_column("event_id", &Event::event_id),
      make_column("event_name", &Event::event_name),
      make_column("start_time", &Event::start_time),
      make_column("end_time", &Event::end_time),
      make_column("created_at", &Event::created_at));

  // Create table if it does not exist
  sqlite::create_table_if_not_exists(db, eventTable);

  // Insert or replace events into the Event table
  {
    sqlite::Transaction tx(db);
    for (const auto& ev : events) {
      sqlite::insert_or_replace(db, eventTable, ev);
    }
    tx.commit();
  }

  // Define metadata for the result row mapping to TemporalAnalysis
  auto analysisTable = make_row_metadata<TemporalAnalysis>(
      make_column("event_id", &TemporalAnalysis::event_id),
      make_column("event_name", &TemporalAnalysis::event_name),
      make_column("start_day", &TemporalAnalysis::start_day),
      make_column("start_month", &TemporalAnalysis::start_month),
      make_column("start_year", &TemporalAnalysis::start_year),
      make_column("start_hour", &TemporalAnalysis::start_hour),
      make_column("start_minute", &TemporalAnalysis::start_minute),
      make_column("start_second", &TemporalAnalysis::start_second),
      make_column("start_weekday", &TemporalAnalysis::start_weekday),
      make_column("start_epoch", &TemporalAnalysis::start_epoch),
      make_column("duration_days", &TemporalAnalysis::duration_days));

  // Build SQL that is compatible with SQLite, approximating the reference SQL.
  //
  // - DAY(), MONTH(), YEAR() are emulated via strftime
  // - HOUR(), MINUTE(), SECOND() via strftime
  // - WEEKDAY() approximated as: (strftime('%w', ts) + 6) % 7  (Mon=0..Sun=6)
  // - UNIXEPOCH() is strftime('%s', ts)
  // - DAYS_BETWEEN(a, b) approximated as (julianday(b) - julianday(a))
  //
  // Note: duration_days is returned as REAL; we map to std::optional<double>.
  const char* sql =
      "SELECT "
      "  event_id, "
      "  event_name, "
      "  CAST(strftime('%d', start_time) AS INTEGER) AS start_day, "
      "  CAST(strftime('%m', start_time) AS INTEGER) AS start_month, "
      "  CAST(strftime('%Y', start_time) AS INTEGER) AS start_year, "
      "  CAST(strftime('%H', start_time) AS INTEGER) AS start_hour, "
      "  CAST(strftime('%M', start_time) AS INTEGER) AS start_minute, "
      "  CAST(strftime('%S', start_time) AS INTEGER) AS start_second, "
      "  ((CAST(strftime('%w', start_time) AS INTEGER) + 6) % 7) AS start_weekday, "
      "  CAST(strftime('%s', start_time) AS INTEGER) AS start_epoch, "
      "  (julianday(end_time) - julianday(start_time)) AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL";

  std::vector<TemporalAnalysis> results;
  sqlite::query(db, sql, analysisTable, [&](const TemporalAnalysis& row) {
    results.push_back(row);
  });

  return results;
}

}  // namespace analyze_temporal_data
