#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

// -----------------------------------------------------------------------------
// Schema matching the problem statement
// -----------------------------------------------------------------------------

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  std::string join_date;  // store as text in "YYYY-MM-DD HH:MM:SS"
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating SQL tables for User and Friendship
 * in SQLite database "test_db.sqlite" and running several analysis queries.
 *
 * Returns: std::vector<FriendConnection> – here used to return one of the
 * analysis results (mutual friends pairs with at least one mutual friend).
 */
std::vector<FriendConnection> analyze_social_network_impl(
    const std::vector<User>& users,
    const std::vector<Friendship>& friendships) {

  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");

  // Drop if they exist so the function is idempotent for this exercise
  conn.execute(R"(DROP TABLE IF EXISTS Friendship;)");
  conn.execute(R"(DROP TABLE IF EXISTS User;)");

  // Create User table
  conn.execute(R"(
    CREATE TABLE User (
      user_id     INTEGER PRIMARY KEY,
      username    VARCHAR(50)  NOT NULL UNIQUE,
      email       VARCHAR(100) NOT NULL UNIQUE,
      join_date   DATETIME     NOT NULL,
      city        VARCHAR(50)
    );
  )");

  // Create Friendship table
  conn.execute(R"(
    CREATE TABLE Friendship (
      user_id1        INTEGER NOT NULL,
      user_id2        INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    );
  )");

  // ---------------------------------------------------------------------------
  // Insert data using sqlgen
  // ---------------------------------------------------------------------------

  {
    // Use a transaction for efficiency and consistency
    sqlite::transaction tx(conn);

    // Insert Users
    {
      std::string sql =
          "INSERT INTO User (user_id, username, email, join_date, city) "
          "VALUES (?1, ?2, ?3, ?4, ?5);";
      sqlite::statement stmt(conn, sql);

      for (const auto& u : users) {
        stmt.reset();
        stmt.bind(1, u.user_id.value());
        stmt.bind(2, u.username);
        stmt.bind(3, u.email);
        stmt.bind(4, u.join_date);
        if (u.city.has_value()) {
          stmt.bind(5, *u.city);
        } else {
          stmt.bind_null(5);
        }
        stmt.step();
      }
    }

    // Insert Friendships (store as undirected, but with a canonical ordering
    // so PRIMARY KEY(user_id1, user_id2) is consistent)
    {
      std::string sql =
          "INSERT OR IGNORE INTO Friendship "
          "(user_id1, user_id2, friendship_date) "
          "VALUES (?1, ?2, ?3);";
      sqlite::statement stmt(conn, sql);

      for (const auto& f : friendships) {
        int uid1 = f.user1_id;
        int uid2 = f.user2_id;
        if (uid2 < uid1) std::swap(uid1, uid2);  // canonical order

        stmt.reset();
        stmt.bind(1, uid1);
        stmt.bind(2, uid2);
        stmt.bind(3, f.created_at.to_string());
        stmt.step();
      }
    }

    tx.commit();
  }

  // ---------------------------------------------------------------------------
  // 1. SELF-JOIN to find mutual friends (pairs that share at least 1 friend)
  // ---------------------------------------------------------------------------

  std::vector<FriendConnection> mutual_friend_pairs;

  {
    // Use the reference-style query, slightly adapted to schema
    const char* sql = R"SQL(
      SELECT u1.username AS user1_name,
             u2.username AS user2_name,
             COUNT(DISTINCT f1.user_id2) AS mutual_friends
      FROM Friendship f1
      JOIN Friendship f2
        ON f1.user_id2 = f2.user_id2
       AND f1.user_id1 < f2.user_id1
      JOIN User u1 ON u1.user_id = f1.user_id1
      JOIN User u2 ON u2.user_id = f2.user_id1
      WHERE EXISTS (
        SELECT 1
        FROM Friendship f3
        WHERE (f3.user_id1 = f1.user_id1 AND f3.user_id2 = f2.user_id1)
           OR (f3.user_id2 = f1.user_id1 AND f3.user_id1 = f2.user_id1)
      )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(DISTINCT f1.user_id2) > 0;
    )SQL";

    sqlite::statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      FriendConnection fc;
      fc.user1_name = stmt.column_text(0);
      fc.user2_name = stmt.column_text(1);
      mutual_friend_pairs.push_back(std::move(fc));
    }
  }

  // ---------------------------------------------------------------------------
  // 2. Nested query: users with more than N friends (here N = given threshold)
  //    Use subquery and aggregation.
  // ---------------------------------------------------------------------------

  {
    int threshold = 3;  // Example N; adjust as needed

    const char* sql = R"SQL(
      SELECT u.user_id,
             u.username,
             COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f
        ON u.user_id = f.user_id1
        OR u.user_id = f.user_id2
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT ?1
      )
      ORDER BY friend_count DESC;
    )SQL";

    sqlite::statement stmt(conn, sql);
    stmt.bind(1, threshold);

    while (stmt.step() == SQLITE_ROW) {
      // We don't return these, but this demonstrates the nested query.
      int user_id = stmt.column_int(0);
      std::string username = stmt.column_text(1);
      int friend_count = stmt.column_int(2);
      (void)user_id;
      (void)username;
      (void)friend_count;
    }
  }

  // ---------------------------------------------------------------------------
  // 3. Friend-of-friend relationships (connected via exactly one mutual friend)
  // ---------------------------------------------------------------------------

  {
    const char* sql = R"SQL(
      SELECT DISTINCT u1.username AS user1_name,
                      u3.username AS user2_name
      FROM Friendship f1
      JOIN Friendship f2
        ON (f1.user_id2 = f2.user_id1 OR f1.user_id2 = f2.user_id2)
      JOIN User u1 ON u1.user_id = f1.user_id1
      JOIN User u3 ON (
           u3.user_id = CASE
              WHEN f2.user_id1 = f1.user_id2 THEN f2.user_id2
              ELSE f2.user_id1
           END
      )
      WHERE u1.user_id < u3.user_id
        -- ensure they are not already friends
        AND NOT EXISTS (
          SELECT 1
          FROM Friendship f3
          WHERE (f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id)
             OR (f3.user_id2 = u1.user_id AND f3.user_id1 = u3.user_id)
        );
    )SQL";

    sqlite::statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      std::string user1_name = stmt.column_text(0);
      std::string user2_name = stmt.column_text(1);
      (void)user1_name;
      (void)user2_name;
    }
  }

  // ---------------------------------------------------------------------------
  // 4. Count friends per user and identify the most connected users
  // ---------------------------------------------------------------------------

  {
    const char* sql = R"SQL(
      WITH friend_counts AS (
        SELECT u.user_id,
               u.username,
               COUNT(DISTINCT CASE
                 WHEN f.user_id1 = u.user_id THEN f.user_id2
                 WHEN f.user_id2 = u.user_id THEN f.user_id1
               END) AS friend_count
        FROM User u
        LEFT JOIN Friendship f
          ON u.user_id = f.user_id1
          OR u.user_id = f.user_id2
        GROUP BY u.user_id, u.username
      )
      SELECT username, friend_count
      FROM friend_counts
      WHERE friend_count = (
        SELECT MAX(friend_count) FROM friend_counts
      );
    )SQL";

    sqlite::statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      std::string username = stmt.column_text(0);
      int friend_count = stmt.column_int(1);
      (void)username;
      (void)friend_count;
    }
  }

  // ---------------------------------------------------------------------------
  // 5. Recommendation: users in the same city who are not yet friends
  // ---------------------------------------------------------------------------

  {
    const char* sql = R"SQL(
      SELECT u1.username AS user1_name,
             u2.username AS user2_name,
             u1.city
      FROM User u1
      JOIN User u2
        ON u1.city IS NOT NULL
       AND u1.city = u2.city
       AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1
        FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id2 = u1.user_id AND f.user_id1 = u2.user_id)
      );
    )SQL";

    sqlite::statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      std::string user1_name = stmt.column_text(0);
      std::string user2_name = stmt.column_text(1);
      std::string city = stmt.column_text(2);
      (void)user1_name;
      (void)user2_name;
      (void)city;
    }
  }

  // For this function, return the mutual-friend connections
  return mutual_friend_pairs;
}

}  // namespace analyze_social_network
