  EXPECT_NEAR(laptop.sin_discount, std::sin(15.5), 1e-6);
  EXPECT_NEAR(laptop.cos_discount, std::cos(15.5), 1e-6);
  EXPECT_NEAR(laptop.tan_discount, std::tan(15.5), 1e-6);

