  EXPECT_DOUBLE_EQ(mouse.abs_price, 25.50);
  EXPECT_DOUBLE_EQ(mouse.ceil_price, 26.0);
  EXPECT_DOUBLE_EQ(mouse.floor_price, 25.0);

