namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;

  // Open (or create) the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Register the Product struct mapping and ensure the Product table exists.
  // Assumes sqlgen is able to infer fields from the struct layout.
  auto productTable = make_table<Product>("Product",
      &Product::product_id, &Product::name, &Product::price,
      &Product::quantity, &Product::discount_rate);

  productTable.create_if_not_exists(db);

  // Clear existing rows so that analysis is based solely on the provided input.
  {
    auto del = db.prepare("DELETE FROM Product;");
    del.step();
  }

  // Insert given products
  {
    auto inserter = productTable.insert(db);
    for (const auto& p : products) {
      inserter.values(p);
      inserter.execute();
      inserter.reset();
    }
  }

  // Run the mathematical operations query
  const char* sql = R"SQL(
    SELECT 
      product_id,
      name,
      ABS(price) AS abs_price,
      CEIL(price) AS ceil_price,
      FLOOR(price) AS floor_price,
      ROUND(price, 2) AS rounded_price,
      EXP(discount_rate / 100.0) AS exp_discount,
      LN(price) AS ln_price,
      LOG2(quantity) AS log2_quantity,
      SIN(discount_rate) AS sin_discount,
      COS(discount_rate) AS cos_discount,
      TAN(discount_rate) AS tan_discount,
      SQRT(quantity) AS sqrt_quantity
    FROM Product;
  )SQL)";

  std::vector<MathAnalysis> result;
  auto stmt = db.prepare(sql);
  while (stmt.step()) {
    MathAnalysis m{};
    int col = 0;
    m.product_id     = stmt.column_int(col++);
    m.name           = stmt.column_text(col++);
    m.abs_price      = stmt.column_double(col++);
    m.ceil_price     = stmt.column_double(col++);
    m.floor_price    = stmt.column_double(col++);
    m.rounded_price  = stmt.column_double(col++);
    m.exp_discount   = stmt.column_double(col++);
    m.ln_price       = stmt.column_double(col++);
    m.log2_quantity  = stmt.column_double(col++);
    m.sin_discount   = stmt.column_double(col++);
    m.cos_discount   = stmt.column_double(col++);
    m.tan_discount   = stmt.column_double(col++);
    m.sqrt_quantity  = stmt.column_double(col++);

    result.push_back(std::move(m));
  }

  return result;
}

