/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::database db("test_db.sqlite");

  // Ensure the OrderItem table exists with the expected schema
  // This will create the table if it doesn't already exist.
  db.exec(R"SQL(
    CREATE TABLE IF NOT EXISTS OrderItem (
      item_id      INTEGER PRIMARY KEY,
      order_id     INTEGER NOT NULL,
      product_id   INTEGER NOT NULL,
      unit_price   REAL    NOT NULL,
      quantity     INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate      REAL
    );
  )SQL");

  // Clear existing data to make this function self‑contained for the demo
  db.exec("DELETE FROM OrderItem;");

  // Insert the provided items into the OrderItem table
  {
    sqlite::statement insert_stmt(
        db,
        "INSERT INTO OrderItem (item_id, order_id, product_id, unit_price, quantity, "
        "discount_rate, tax_rate) VALUES (?, ?, ?, ?, ?, ?, ?);");

    for (const auto& it : items) {
      insert_stmt.reset();
      insert_stmt.bind(1, static_cast<int>(it.item_id));  // PrimaryKey wrapper -> underlying int
      insert_stmt.bind(2, it.order_id);
      insert_stmt.bind(3, it.product_id);
      insert_stmt.bind(4, it.unit_price);
      insert_stmt.bind(5, it.quantity);

      if (it.discount_rate.has_value()) {
        insert_stmt.bind(6, *it.discount_rate);
      } else {
        insert_stmt.bind_null(6);
      }

      if (it.tax_rate.has_value()) {
        insert_stmt.bind(7, *it.tax_rate);
      } else {
        insert_stmt.bind_null(7);
      }

      insert_stmt.step();
    }
  }

  // Use SQL to calculate the requested arithmetic and business metrics
  const char* query = R"SQL(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) AS discount_rate,
      COALESCE(tax_rate, 0) AS tax_rate,
      (unit_price * quantity) AS gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0)) AS discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0) *
       (1 + COALESCE(tax_rate, 0)/100.0)) AS final_total,
      -- Safe division for unit_cost (if quantity is 0, result is 0)
      CASE
        WHEN quantity = 0 THEN 0.0
        ELSE (unit_price * quantity / quantity)
      END AS unit_cost,
      (quantity % 10) AS quantity_group,
      (unit_price * 0.3) AS estimated_profit
    FROM OrderItem;
  )SQL";

  sqlite::statement stmt(db, query);

  std::vector<OrderMetrics> results;
  while (stmt.step()) {
    OrderMetrics m{};
    int col = 0;

    m.item_id         = stmt.column_int(col++);
    m.order_id        = stmt.column_int(col++);
    m.product_id      = stmt.column_int(col++);
    m.unit_price      = stmt.column_double(col++);
    m.quantity        = stmt.column_int(col++);
    m.discount_rate   = stmt.column_double(col++);
    m.tax_rate        = stmt.column_double(col++);
    m.gross_total     = stmt.column_double(col++);
    m.discounted_total= stmt.column_double(col++);
    m.final_total     = stmt.column_double(col++);
    m.unit_cost       = stmt.column_double(col++);
    m.quantity_group  = stmt.column_int(col++);
    m.estimated_profit= stmt.column_double(col++);

    results.push_back(m);
  }

  return results;
}

}  // namespace calculate_order_metrics
