 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Open SQLite connection to the specified database.
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Define table mappings for sqlgen.
  auto customers = sqlgen::table<Customer>("Customer",
                                           &Customer::customer_id,
                                           &Customer::name);

  auto orders = sqlgen::table<Order>("Order",
                                     &Order::order_id,
                                     &Order::customer_id,
                                     &Order::order_date);

  auto payments = sqlgen::table<Payment>("Payment",
                                         &Payment::payment_id,
                                         &Payment::order_id,
                                         &Payment::amount);

  // Define the consolidated (projection) table mapping.
  // Note that this does not correspond to a real DB table, but to the
  // selected columns of the JOIN query.
  auto consolidated = sqlgen::table<Consolidated>("",
                                                  &Consolidated::order_id,
                                                  &Consolidated::customer_name,
                                                  &Consolidated::amount);

  using namespace sqlgen;

  // Build and execute the JOIN query:
  // SELECT o.order_id, c.name AS customer_name, p.amount
  // FROM Order o
  // INNER JOIN Customer c ON o.customer_id = c.customer_id
  // INNER JOIN Payment p ON o.order_id = p.order_id
  // ORDER BY p.amount DESC;
  auto results = select(consolidated.columns())
                   .from(orders)
                   .join(customers, orders(&Order::customer_id) ==
                                      customers(&Customer::customer_id))
                   .join(payments, orders(&Order::order_id) ==
                                     payments(&Payment::order_id))
                   .order_by(desc(payments(&Payment::amount)))
                   .execute<Consolidated>(conn);

  return results;
}

}  // namespace join_orders_customers_payments
