```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to the SQLite database "test_db.sqlite"
  sqlgen::sqlite::connection conn{"test_db.sqlite"};

  // Create a mapper for the Note struct so sqlgen can interact with the Notes table.
  // We assume the underlying table name is "Notes" and has columns "note_id" and "content".
  sqlgen::mapper<Note> note_mapper{
      "Notes",
      sqlgen::make_columns(
          &Note::note_id, "note_id",
          &Note::content, "content")};

  // 1. Update all rows: replace all occurrences of "foo" with "bar" in content.
  //
  // Use SQLite's REPLACE(string, search, replace) to update content in-place
  // for every row that actually contains "foo".
  //
  // UPDATE Notes
  // SET content = REPLACE(content, 'foo', 'bar')
  // WHERE content LIKE '%foo%';
  conn.execute(
      "UPDATE Notes "
      "SET content = REPLACE(content, 'foo', 'bar') "
      "WHERE content LIKE '%foo%';");

  // 2. Read back all notes for verification and return them
  //    as UpdatedNote objects (with updated_content field).
  std::vector<Note> notes = note_mapper.get_all(conn);

  std::vector<UpdatedNote> result;
  result.reserve(notes.size());
  for (const auto& n : notes) {
    UpdatedNote u;
    u.note_id = n.note_id;
    u.updated_content = n.content;
    result.push_back(std::move(u));
  }

  return result;
}

}  // namespace replace_text_in_notes
