#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool indicating whether child rows were deleted automatically.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");

  // Ensure foreign keys are enforced in SQLite
  conn.execute("PRAGMA foreign_keys = ON;");

  // Drop tables if they exist to have a clean slate
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Register models with sqlgen
  Database db;
  db.registerModel<Parent>();
  db.registerModel<Child>();

  // Generate and execute CREATE TABLE statements
  {
    auto stmts = db.createAll<sqlite::dialect>();
    for (const auto &sql : stmts) {
      conn.execute(sql);
    }
  }

  // At this point, Child.parent_id is a FK to Parent.parent_id, but we must
  // ensure ON DELETE CASCADE is present. If the sqlgen mapping doesn’t emit
  // ON DELETE CASCADE automatically for this ForeignKey, we can enforce it
  // by recreating the Child table. However, assuming the library uses the
  // ForeignKey<> type with ON DELETE CASCADE by default, the above CREATE
  // is sufficient. If not, you could explicitly execute:
  //
  // conn.execute(
  //   "DROP TABLE IF EXISTS Child;"
  //   "CREATE TABLE Child ("
  //   "  child_id INTEGER PRIMARY KEY,"
  //   "  parent_id INTEGER REFERENCES Parent(parent_id) ON DELETE CASCADE,"
  //   "  note TEXT"
  //   ");"
  // );

  // Insert a parent record
  {
    Parent p;
    p.parent_id = 1;
    p.name = "Parent 1";
    db.insert(conn, p);
  }

  // Insert child records referencing the parent
  {
    Child c1;
    c1.child_id = 1;
    c1.parent_id = 1;
    c1.note = "Child 1 of Parent 1";
    db.insert(conn, c1);

    Child c2;
    c2.child_id = 2;
    c2.parent_id = 1;
    c2.note = "Child 2 of Parent 1";
    db.insert(conn, c2);
  }

  // Delete the parent
  {
    Parent p;
    p.parent_id = 1;
    // sqlgen typically deletes by primary key if the key is set.
    db.remove(conn, p);
  }

  // Verify whether child rows are deleted automatically
  // Count rows in Child table
  int remaining_children = 0;
  conn.query("SELECT COUNT(*) FROM Child;", [&](auto &stmt) {
    remaining_children = stmt.get<int>(0);
  });

  // If cascade delete worked, there should be 0 child rows remaining
  return remaining_children == 0;
}

}  // namespace cascade_delete_demo
