```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;

  try {
    // 1. Connect to the SQLite database "test_db.sqlite"
    sqlite::Connection conn("test_db.sqlite");

    // 2. Bind the Account struct to a table and create it
    auto db = make_db(conn,
                      make_table<Account>("Account",
                                          &Account::account_id,
                                          &Account::balance,
                                          &Account::status));

    // Ensure the table exists (create if not present)
    db.sync_schema();

    // Clear any existing data to make the example deterministic
    db.remove_all<Account>();

    // Insert some initial data
    Account a1{PrimaryKey<int>{1}, 100.0, "active"};
    Account a2{PrimaryKey<int>{2}, 200.0, "active"};
    Account a3{PrimaryKey<int>{3}, 300.0, "inactive"};

    db.insert(a1);
    db.insert(a2);
    db.insert(a3);

    // 3. Update balances and statuses using set(...)

    // Example 1: Give a bonus of 50.0 to all active accounts
    // UPDATE Account SET balance = balance + 50 WHERE status = 'active';
    db.update<Account>(
        set(&Account::balance = &Account::balance + 50.0),
        where(c(&Account::status) == "active"));

    // Example 2: Mark low-balance accounts as 'inactive'
    // UPDATE Account SET status = 'inactive' WHERE balance < 200;
    db.update<Account>(
        set(&Account::status = "inactive"),
        where(c(&Account::balance) < 200.0));

    // Example 3: Set both balance and status for a specific account
    // UPDATE Account SET balance = 500, status = 'vip' WHERE account_id = 3;
    db.update<Account>(
        set(&Account::balance = 500.0,
            &Account::status  = "vip"),
        where(c(&Account::account_id) == 3));

    // 4. Verify changes persisted

    // Fetch all accounts
    auto accounts = db.get_all<Account>();

    // We expect three accounts
    if (accounts.size() != 3) {
      return false;
    }

    // Helper lambda to find account by id
    auto find_by_id = [&](int id) -> const Account* {
      for (const auto& acc : accounts) {
        if (acc.account_id.value == id) {
          return &acc;
        }
      }
      return nullptr;
    };

    const Account* acc1 = find_by_id(1);
    const Account* acc2 = find_by_id(2);
    const Account* acc3 = find_by_id(3);

    if (!acc1 || !acc2 || !acc3) {
      return false;
    }

    // Initial:
    // id 1: 100, active
    // id 2: 200, active
    // id 3: 300, inactive
    //
    // After Example 1 (bonus +50 to active):
    // id 1: 150, active
    // id 2: 250, active
    // id 3: 300, inactive
    //
    // After Example 2 (low balance <200 -> inactive):
    // id 1: 150, inactive
    // id 2: 250, active
    // id 3: 300, inactive
    //
    // After Example 3 (id 3 -> balance 500, status vip):
    // id 1: 150, inactive
    // id 2: 250, active
    // id 3: 500, vip

    // Simple numeric comparisons with some tolerance for floating point
    auto approx_equal = [](double a, double b, double eps = 1e-9) {
      return (a - b < eps) && (b - a < eps);
    };

    if (!approx_equal(acc1->balance, 150.0) || acc1->status != "inactive") {
      return false;
    }

    if (!approx_equal(acc2->balance, 250.0) || acc2->status != "active") {
      return false;
    }

    if (!approx_equal(acc3->balance, 500.0) || acc3->status != "vip") {
      return false;
    }

    return true;
  } catch (...) {
    // Any failure in DB operations means the demonstration is not successful
    return false;
  }
}

}  // namespace update_set_operations
```

