```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 *
 * Since SQLite does not support FULL OUTER JOIN directly, this is implemented as:
 *   (LEFT JOIN suppliers -> products)
 *   UNION ALL
 *   (RIGHT JOIN suppliers <- products, emulated with LEFT JOIN and IS NULL)
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to SQLite database "test_db.sqlite" using sqlgen
  sqlgen::sqlite::database db("test_db.sqlite");

  // Ensure sqlgen knows about the mapped types (no-op if already registered)
  db.register_type<Supplier>("Supplier");
  db.register_type<Product>("Product");

  // We want all suppliers with their products (if any), plus any products
  // whose supplier_id doesn't correspond to an existing supplier.
  //
  // The SupProd structure:
  //   supplier_name: always present (string)
  //   product_name:  optional (NULLable in SQL)
  //
  // For rows that come from "products without suppliers", we still need a
  // supplier_name. Since the requirement is to include "all suppliers and
  // products" and the struct has non-optional supplier_name, we will use
  // the product's name as supplier_name when a real supplier is missing.
  //
  // This keeps the example simple while satisfying the function signature.

  // The SQL uses UNION ALL of:
  // 1) LEFT JOIN: all suppliers + matching products
  // 2) "RIGHT JOIN" emulation: all products where there is no supplier,
  //    using the product name as the supplier_name field.
  static const char* sql = R"SQL(
    SELECT
      s.name AS supplier_name,
      p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p
      ON s.supplier_id = p.supplier_id

    UNION ALL

    SELECT
      p.name AS supplier_name,
      NULL AS product_name
    FROM Product p
    LEFT JOIN Supplier s
      ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL;
  )SQL";

  sqlgen::statement stmt = db.prepare(sql);

  std::vector<SupProd> results;

  // Execute the query and fetch rows
  while (stmt.step()) {
    SupProd row;

    // Column 0: supplier_name (TEXT, never NULL in our SELECT)
    row.supplier_name = stmt.get<std::string>(0);

    // Column 1: product_name (TEXT, can be NULL)
    if (stmt.is_null(1)) {
      row.product_name = std::nullopt;
    } else {
      row.product_name = stmt.get<std::string>(1);
    }

    results.push_back(std::move(row));
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

