```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating SQL tables in test_db.sqlite, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  JoinAnalysis analysis;

  // Connect to the SQLite database "test_db.sqlite"
  Database db("test_db.sqlite");

  // Ensure tables exist with the expected schema
  db.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS Department (
      department_id   INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location        TEXT
    );
  )SQL");

  db.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id   INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name    TEXT NOT NULL,
      last_name     TEXT NOT NULL,
      salary        REAL NOT NULL,
      FOREIGN KEY(department_id) REFERENCES Department(department_id)
    );
  )SQL");

  // For demonstration / analysis purposes, clear existing rows so that the
  // results reflect only the provided in‑memory data.
  db.execute("DELETE FROM Employee;");
  db.execute("DELETE FROM Department;");

  // Insert provided Department rows
  {
    auto inserter = db.inserter<Department>("Department");
    for (const auto& d : depts) {
      inserter.insert(d);
    }
  }

  // Insert provided Employee rows
  {
    auto inserter = db.inserter<Employee>("Employee");
    for (const auto& e : emps) {
      inserter.insert(e);
    }
  }

  // Helper lambda to run a query and collect JoinResult rows
  auto collect_results = [&db](const std::string& sql,
                               std::vector<JoinResult>& out_vec) {
    Statement stmt = db.prepare(sql);
    while (stmt.step()) {
      JoinResult jr;

      // Column order: department_name, first_name, last_name, salary
      if (stmt.column_type(0) != SQLITE_NULL) {
        jr.department_name = stmt.column_text(0);
      }
      if (stmt.column_type(1) != SQLITE_NULL) {
        jr.first_name = stmt.column_text(1);
      }
      if (stmt.column_type(2) != SQLITE_NULL) {
        jr.last_name = stmt.column_text(2);
      }
      if (stmt.column_type(3) != SQLITE_NULL) {
        jr.salary = stmt.column_double(3);
      }

      out_vec.push_back(std::move(jr));
    }
  };

  // INNER JOIN: employees with assigned departments
  collect_results(
      R"SQL(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        INNER JOIN Employee e ON d.department_id = e.department_id
        ORDER BY d.department_name, e.last_name, e.first_name;
      )SQL",
      analysis.inner_join_results);

  // LEFT JOIN: all employees (even without departments)
  collect_results(
      R"SQL(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Employee e
        LEFT JOIN Department d ON e.department_id = d.department_id
        ORDER BY e.last_name, e.first_name;
      )SQL",
      analysis.left_join_results);

  // RIGHT JOIN emulation for SQLite:
  // RIGHT JOIN Department d ON e.department_id = d.department_id
  // is equivalent to:
  //   SELECT d..., e...
  //   FROM Department d
  //   LEFT JOIN Employee e ON e.department_id = d.department_id;
  collect_results(
      R"SQL(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        LEFT JOIN Employee e ON e.department_id = d.department_id
        ORDER BY d.department_name, e.last_name, e.first_name;
      )SQL",
      analysis.right_join_results);

  // FULL OUTER JOIN emulation for SQLite:
  //
  // FULL JOIN = rows in (Department ⋈ Employee)
  //           ∪ rows in Department with no Employee
  //           ∪ rows in Employee with no Department
  //
  // We can construct it as UNION of:
  // 1) left join:  Department d LEFT JOIN Employee e ...
  // 2) left join:  Employee e LEFT JOIN Department d ...
  //    where department side is NULL (i.e., unmatched employees)
  //
  // To keep the result schema identical, we always select:
  //   department_name, first_name, last_name, salary
  collect_results(
      R"SQL(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        LEFT JOIN Employee e ON e.department_id = d.department_id
        UNION
        SELECT d2.department_name, e2.first_name, e2.last_name, e2.salary
        FROM Employee e2
        LEFT JOIN Department d2 ON e2.department_id = d2.department_id
        WHERE d2.department_id IS NULL
        ORDER BY department_name, last_name, first_name;
      )SQL",
      analysis.full_join_results);

  return analysis;
}

}  // namespace analyze_department_employees
```

