                  .from<Product>()
                  .join<Sales>(on(Product::product_id == Sales::product_id))
                  .group_by(Product::product_id,
                            Product::product_name,
                            Product::category)
                  .order_by(desc(column<double>("total_sales")))
                  .limit(static_cast<int>(limit_count))
                  .prepare(conn);

  std::vector<TopProduct> results;
  results.reserve(limit_count);

  // Execute and map rows to TopProduct
