namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 *
 * Notes:
 * - Connects to "test_db.sqlite" using sqlgen's SQLite backend.
 * - Computes weekday using SQLite's strftime('%w', sale_time), where:
 *     0 = Sunday, 1 = Monday, ..., 6 = Saturday.
 * - Aggregates total quantity per weekday and returns the results ordered by weekday.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open connection to the SQLite database
  sqlite::Connection conn("test_db.sqlite");

  // We use a raw SQL query because we need SQLite's strftime to extract weekday.
  // The query:
  //   - CAST(strftime('%w', sale_time) AS INTEGER) gives weekday 0..6.
  //   - SUM(quantity) gives total quantity sold for that weekday.
  //   - GROUP BY weekday to aggregate.
  //   - ORDER BY weekday for deterministic ordering in the result.
  constexpr auto query_text =
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "       SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday "
      "ORDER BY weekday";

  auto stmt = conn.prepare(query_text);

  std::vector<WeekdayStats> results;
  while (stmt.step()) {
    WeekdayStats ws;
    ws.weekday = stmt.column_int(0);
    ws.total_quantity = stmt.column_int(1);
    results.push_back(ws);
  }

  return results;
}

}  // namespace weekday_sales_analysis
