  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 *
 * Notes:
 * - Connects to "test_db.sqlite" using sqlgen's SQLite backend.
 * - Uses SQLite date/time functions to extract components from start_time.
 * - Computes duration in days using julianday(end_time) - julianday(start_time).
 * - Groups results by project and calendar week (week starts Monday),
 *   aggregating by SUM of daily durations for that week.
 */
std::vector<TimeMetrics> project_time_tracking() {
  // Open SQLite database via sqlgen
  sqlgen::sqlite::Database db("test_db.sqlite");

  // We’ll implement "weekly grouped metrics" as aggregation per project per
  // calendar week using SQLite's strftime('%Y-%W', start_time) as a week key.
  //
  // For each (project, week) we select:
  //  - project_id
  //  - name
  //  - day / month / year / hour / minute / second taken from the first
  //    start_time in that week (via MIN(start_time))
  //  - duration_days as SUM(days between start and end) in that week
  //
  // Note: SQLite has no DAY/MONTH/YEAR/HOUR/MINUTE/SECOND functions; use strftime.
  const char* query = R"SQL(
    SELECT
      p.project_id AS project_id,
      p.name       AS name,

      -- Extract components from the first start_time in the week
      CAST(strftime('%d', MIN(t.start_time)) AS INTEGER) AS day,
      CAST(strftime('%m', MIN(t.start_time)) AS INTEGER) AS month,
      CAST(strftime('%Y', MIN(t.start_time)) AS INTEGER) AS year,
      CAST(strftime('%H', MIN(t.start_time)) AS INTEGER) AS hour,
      CAST(strftime('%M', MIN(t.start_time)) AS INTEGER) AS minute,
      CAST(strftime('%S', MIN(t.start_time)) AS INTEGER) AS second,

      -- Duration in days over the whole week
      SUM(julianday(t.end_time) - julianday(t.start_time)) AS duration_days

    FROM Project p
    INNER JOIN TimeLog t
      ON p.project_id = t.project_id

    -- Weekly grouping key: calendar year + week number
    GROUP BY
      p.project_id,
      p.name,
      strftime('%Y-%W', t.start_time)

    ORDER BY
      p.project_id,
      strftime('%Y-%W', t.start_time)
  )SQL";

  sqlgen::sqlite::Statement stmt = db.prepare(query);

  std::vector<TimeMetrics> result;
  while (stmt.step()) {
    TimeMetrics m{};
    m.project_id   = stmt.get<int>(0);
    m.name         = stmt.get<std::string>(1);
    m.day          = stmt.get<int>(2);
    m.month        = stmt.get<int>(3);
    m.year         = stmt.get<int>(4);
    m.hour         = stmt.get<int>(5);
    m.minute       = stmt.get<int>(6);
    m.second       = stmt.get<int>(7);
    m.duration_days = stmt.get<double>(8);
    result.push_back(std::move(m));
  }

  return result;
}

}  // namespace project_time_tracking
